// ── Date helpers (UTC, date-only — no timezone drift) ─────────────────────────
function toUTC(d: Date | string): number {
  const x = typeof d === "string" ? new Date(d + "T00:00:00Z") : d;
  return Date.UTC(x.getUTCFullYear(), x.getUTCMonth(), x.getUTCDate());
}

/** Whole days from `from` to `to` (negative if `to` is in the past). */
export function daysBetween(from: Date | string, to: Date | string): number {
  return Math.round((toUTC(to) - toUTC(from)) / 86_400_000);
}

export function formatDate(iso: string): string {
  return new Date(iso + "T00:00:00Z").toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
    timeZone: "UTC",
  });
}

// ── The engine: build a dated study plan from today + the student's profile ───
export type StudyPlanInputs = {
  today: Date;
  graduationYear?: number;
  faculties: string[];
  satScore?: number;
};

export type SatStep = {
  test: string;
  regDeadline: string;
  daysToDeadline: number;
  registrationOpen: boolean; // deadline hasn't passed
  lastBeforeApps: boolean; // last sitting whose scores land before app deadlines
};

export type CompetitionStep = Competition & { daysToDeadline: number };

export type Deadline = { label: string; date: string; daysLeft: number };

export type StudyPlan = {
  cycleLabel: string | null;
  satScore?: number;
  satStrong: boolean; // already a strong score → SAT is optional polish
  satSteps: SatStep[];
  competitions: CompetitionStep[];
  deadlines: Deadline[];
};

const SAT_STRONG = 1500;

export function buildStudyPlan({
  today,
  graduationYear,
  faculties,
  satScore,
}: StudyPlanInputs): StudyPlan {
  // Application-deadline window from graduation year. A "Class of G" student
  // applies in the fall before — Early ≈ Nov 1 (G-1), Regular ≈ Jan 5 (G).
  let deadlines: Deadline[] = [];
  let earlyDeadlineISO: string | null = null;
  let cycleLabel: string | null = null;
  if (graduationYear) {
    earlyDeadlineISO = `${graduationYear - 1}-11-01`;
    const regularISO = `${graduationYear}-01-05`;
    cycleLabel = `Class of ${graduationYear} · applying in the ${graduationYear - 1}–${String(
      graduationYear
    ).slice(2)} cycle`;
    deadlines = [
      { label: "Early Action / Decision deadline", date: earlyDeadlineISO, daysLeft: daysBetween(today, earlyDeadlineISO) },
      { label: "Regular Decision deadline", date: regularISO, daysLeft: daysBetween(today, regularISO) },
    ].filter((d) => d.daysLeft >= -30); // hide deadlines well in the past
  }

  // SAT sittings whose registration is still open, soonest first. The "last
  // before apps" sitting is the latest test ≥ 3 weeks before the early deadline
  // (scores need time to arrive).
  const openSittings = SAT_SITTINGS.filter(
    (s) => daysBetween(today, s.regDeadline) >= 0
  );
  let lastBeforeIdx = -1;
  if (earlyDeadlineISO) {
    for (let i = 0; i < openSittings.length; i++) {
      if (daysBetween(openSittings[i].test, earlyDeadlineISO) >= 21) lastBeforeIdx = i;
    }
  }
  const satSteps: SatStep[] = openSittings.slice(0, 3).map((s, i) => ({
    test: s.test,
    regDeadline: s.regDeadline,
    daysToDeadline: daysBetween(today, s.regDeadline),
    registrationOpen: true,
    lastBeforeApps: i === lastBeforeIdx,
  }));

  // Competitions matching the student's field(s), nearest deadline first.
  const fac = new Set(faculties);
  const competitions: CompetitionStep[] = COMPETITIONS.filter(
    (c) => c.fields === "all" || c.fields.some((f) => fac.has(f))
  )
    .filter((c) => daysBetween(today, c.deadline) >= 0)
    .map((c) => ({ ...c, daysToDeadline: daysBetween(today, c.deadline) }))
    .sort((a, b) => a.daysToDeadline - b.daysToDeadline)
    .slice(0, 4);

  return {
    cycleLabel,
    satScore,
    satStrong: satScore != null && satScore >= SAT_STRONG,
    satSteps,
    competitions,
    deadlines,
  };
}
